INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Kanpur', 'overview', 'Overview > Facts: IIT Kanpur is located in Kalyanpur, Kanpur, Uttar Pradesh 208016.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Kanpur', 'overview', 'Overview > Facts: IIT Kanpur has 15 halls of residence — 12 for boys and 3 for girls.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Kanpur', 'hostels_boys', 'Hostels Boys > Facts: Hall 13 is the first-year boys hostel at IIT Kanpur.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Kanpur', 'hostels_boys', 'Hostels Boys > Facts: Hall 2, Hall 3, and Hall 5 are for 2nd and 3rd year students.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Kanpur', 'hostels_boys', 'Hostels Boys > Facts: Hall 12 is for 3rd year students with single and double sharing.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Kanpur', 'hostels_boys', 'Hostels Boys > Facts: Hall 7, Hall 9, and Hall 11 are for 4th year students.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Kanpur', 'hostels_boys', 'Hostels Boys > Facts: Hall 1 is for 4th year students with higher responsibilities like General Secretary and Organizer.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Kanpur', 'hostels_boys', 'Hostels Boys > Facts: Hall 8 and Hall 10 are for PhD and higher education students.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Kanpur', 'hostels_boys', 'Hostels Boys > Facts: Hall 14 is for PG and MTech students.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Kanpur', 'hostels_boys', 'Hostels Boys > Facts: Halls 13, 12, 5, 3, 2 have double or triple sharing rooms. Other halls have single sharing.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Kanpur', 'hostels_boys', 'Hostels Boys > Facilities: All halls have canteens, stationery shops, and printout facilities.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Kanpur', 'hostels_boys', 'Hostels Boys > Facilities: All boys halls have barber shops.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Kanpur', 'hostels_boys', 'Hostels Boys > Indoor Games: Halls have table tennis, carrom, and chess.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Kanpur', 'hostels_boys', 'Hostels Boys > Outdoor: Some halls have volleyball courts, cricket grounds, and basketball courts.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Kanpur', 'hostels_girls', 'Hostels Girls > Facts: Hall 4 is for 1st year girls with double/single sharing.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Kanpur', 'hostels_girls', 'Hostels Girls > Facts: Hall 6 is for 2nd, 3rd, and 4th year girls with double/single sharing.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Kanpur', 'hostels_girls', 'Hostels Girls > Facts: Girls Hostel 1 is for PG and higher studies students with double/single sharing.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Kanpur', 'mess', 'Mess > System: Each hall has its own attached mess at IIT Kanpur.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Kanpur', 'mess', 'Mess > Cost: Mess and electricity bills combined cost approximately Rs 4000 per month.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Kanpur', 'mess', 'Mess > Daily Breakfast: Bread, jam, butter, milk (Bournvita/Horlicks/Coffee), egg (2 pcs), tea, dalia, cornflakes.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Kanpur', 'mess', 'Mess > Daily Lunch and Dinner: Roti (plain + buttered), plain rice, pickle, raita/dahi, chicken fried rice.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Kanpur', 'mess', 'Mess > Non-Veg: Chicken fried rice available daily. Butter chicken, fish curry, chilli chicken on rotation.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Kanpur', 'mess', 'Mess > Extras: Neebu Pani/Rasna/Roohafza served with lunch daily.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Kanpur', 'mess', 'Mess > Highlights: Monday breakfast is Aloo Pyaz Paratha. Friday breakfast is Indori Poha with Jalebi.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Kanpur', 'mess', 'Mess > Highlights: Saturday breakfast is Idli, Masala Idli, Wada with Sambhar. Sunday is Mysore Dosa.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Kanpur', 'mess', 'Mess > Online: Mess menu is available at campusmess.in.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Kanpur', 'canteen', 'Canteen > DOAA Canteen at IIT Kanpur is open 24 hours.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Kanpur', 'canteen', 'Canteen > On-campus restaurants: Mama Meow, Tadka Restaurant, Chai Pani Restaurant, Campus Restaurant.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Kanpur', 'canteen', 'Canteen > On-campus chains: Cafe Coffee Day, Starbucks, Burger Singh, Subway, Dominos Pizza.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Kanpur', 'canteen', 'Canteen > Food delivery: Swiggy and Zomato are available at IIT Kanpur.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Kanpur', 'fee_structure', 'Fee > Mess and electricity bills combined cost approximately Rs 4000 per month at IIT Kanpur.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Kanpur', 'wifi', 'WiFi > IIT Kanpur has IITK 5G WiFi network.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Kanpur', 'wifi', 'WiFi > 4G connectivity is available across approximately 90% of the campus.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Kanpur', 'attendance', 'Attendance > Attendance is not mandatory for all courses at IIT Kanpur, it depends on the professor.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Kanpur', 'attendance', 'Attendance > Minimum 75% attendance is required to appear in semester exams.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Kanpur', 'clubs', 'Clubs > Cultural: Anime Society, Book Club, Dance Club (Krazzy O''ve Sync), Debating Society, Design and Animation Club.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Kanpur', 'clubs', 'Clubs > Cultural: Dramatics Club (Fursat Mandli), English Literary Society, Fine Arts Club, Film Club, Hindi Sahitya Sabha.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Kanpur', 'clubs', 'Clubs > Cultural: Humour House, Music Club, Photography Club, Quiz Club, Student Film Society.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Kanpur', 'clubs', 'Clubs > Technical/Sports: Robotics Club, Aero Modeling Club, Skating Club, Motorsport Club.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Kanpur', 'fests', 'Fests > Udghosh is the sports festival held in October at IIT Kanpur.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Kanpur', 'fests', 'Fests > Antaragni is the cultural festival held in October or November.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Kanpur', 'fests', 'Fests > Techkriti is the tech festival held in March.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Kanpur', 'fests', 'Fests > E-Summit is the entrepreneurship event held in February or March.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Kanpur', 'fests', 'Fests > Freshers events include Galaxy and Inferno (held among halls).');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Kanpur', 'sports', 'Sports > Old Sports Complex has gym, skating rink, tennis, volleyball, and basketball.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Kanpur', 'sports', 'Sports > Halls have indoor games: table tennis, carrom, chess. Some have volleyball, cricket, basketball.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Kanpur', 'gym', 'Gym > Most halls have gym facilities free of cost.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Kanpur', 'gym', 'Gym > Old Sports Complex gym costs Rs 350 per month for students.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Kanpur', 'gym', 'Gym > Payment options: monthly, semester, or yearly basis.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Kanpur', 'laundry', 'Laundry > Dhobi service is available in all halls and comes to every room.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Kanpur', 'laundry', 'Laundry > Washing machines are available in halls.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Kanpur', 'laundry', 'Laundry > 1 common laundry facility is available for all students.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Kanpur', 'fines', 'Fines > Late academic or pre-registration fine is Rs 2000 to Rs 2500.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Kanpur', 'medical', 'Medical > IIT Kanpur Health Centre is open 24 hours.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Kanpur', 'medical', 'Medical > Medical services are free as insurance is included in the semester fee.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Kanpur', 'medical', 'Medical > Ambulances are available for emergencies.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Kanpur', 'medical', 'Medical > Up to Rs 1 lakh is reimbursed for outside hospital admissions upon bill submission.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Kanpur', 'transport', 'Transport > Kanpur Central Railway Station is approximately 18 km from IIT Kanpur.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Kanpur', 'transport', 'Transport > Chakeri Airport is approximately 20 km from campus.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Kanpur', 'transport', 'Transport > Jagarkati Bus Stop is approximately 15 km from campus.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Kanpur', 'tourist_places', 'Tourist > Nearby places: Zoological Park, Blueworld Park, Ganga Barrage.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Kanpur', 'tourist_places', 'Tourist > Weekend trips: Agra, Ayodhya, Vrindavan, Varanasi.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Kanpur', 'malls', 'Malls > Nearby malls: Z Square, Max, Vishal Mart, Rave Moti Mall.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Kanpur', 'climate', 'Climate > IIT Kanpur winters go below 6°C.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Kanpur', 'climate', 'Climate > IIT Kanpur summers exceed 45°C. The climate is extreme.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Kanpur', 'language', 'Language > Primary language at IIT Kanpur is Hindi. English is also used.');
